blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie dowiesz się szczegółowo <strong>Present Perfect Passive</strong>: jak tworzyć tę formę, kiedy jej używać i czym różni się ona od innych czasów biernych.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "<strong>Temat + był/był + V3</strong>:",
            "example": "The work has been completed."
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "text": "<strong>Temat + był/był + nie + był + V3</strong>:",
            "example": "The letter has not been sent yet."
        },
        {
            "label": "Pytanie",
            "color": "blue",
            "text": "<strong>Czy/był + Temat + był + V3?</strong>:",
            "example": "Has the project been finished?"
        }
    ]
}

{
    "title": "1. Struktura czasu biernego Present Perfect",
    "intro": "Wybór <strong>ma/miał</strong> zależy od tematu, natomiast <strong>był</strong> pozostaje taki sam:",
    "items": [
        {
            "label": "Ja/Ty/My/Oni",
            "title": "były + V3",
            "subtitle": "Dokumenty zostały podpisane. — Dokumenty są podpisane."
        },
        {
            "label": "On/ona/ono",
            "title": "było + V3",
            "subtitle": "Raport został przesłany. — Sprawozdanie zostało złożone."
        },
        {
            "label": "Mnogi",
            "title": "były + V3",
            "subtitle": "Wszystkie zadania zostały wykonane. - Wszystkie zadania zostały wykonane."
        },
        {
            "label": "Klawisz",
            "title": "było, jest częścią stałą",
            "subtitle": "zawsze poprzedza wersję V3."
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>Temat + był/był + V3 (+ według agenta)</strong>",
            "examples": [
                {
                    "en": "The project has been completed successfully.",
                    "ua": "Projekt został pomyślnie ukończony."
                },
                {
                    "en": "All the tickets have been sold.",
                    "ua": "Wszystkie bilety zostały sprzedane."
                },
                {
                    "en": "The problem has been solved.",
                    "ua": "Problem został rozwiązany."
                },
                {
                    "en": "New rules have been introduced.",
                    "ua": "Wprowadzono nowe zasady."
                }
            ]
        },
        {
            "label": "Skoncentruj się na rezultacie",
            "color": "sky",
            "description": "Kiedy ważny jest <strong>wynik</strong>, a nie proces:",
            "examples": [
                {
                    "en": "The email has been sent. (результат: лист відправлено)",
                    "ua": "List został wysłany."
                },
                {
                    "en": "The decision has been made. (результат: рішення прийнято)",
                    "ua": "Decyzja została podjęta."
                },
                {
                    "en": "The repair has been done. (результат: ремонт зроблено)",
                    "ua": "Naprawa została wykonana."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać strony biernej Present Perfect?",
    "sections": [
        {
            "label": "Zakończone działania z wynikami",
            "color": "emerald",
            "description": "W przypadku działań, które <strong>zakończyły się</strong>, a wynik jest <strong>teraz ważny</strong>:",
            "examples": [
                {
                    "en": "The report has been finished. (готово до перегляду)",
                    "ua": "Raport jest kompletny."
                },
                {
                    "en": "Your application has been approved.",
                    "ua": "Twój wniosek został zatwierdzony."
                },
                {
                    "en": "The system has been updated.",
                    "ua": "System został zaktualizowany."
                }
            ]
        },
        {
            "label": "Ostatnie działania",
            "color": "blue",
            "description": "W przypadku działań, które <strong>właśnie miały miejsce</strong> (właśnie, niedawno):",
            "examples": [
                {
                    "en": "The email has just been sent.",
                    "ua": "E-mail właśnie został wysłany."
                },
                {
                    "en": "The meeting has recently been scheduled.",
                    "ua": "Niedawno zaplanowano spotkanie."
                },
                {
                    "en": "New software has just been installed.",
                    "ua": "Właśnie zainstalowano nowe oprogramowanie."
                }
            ]
        },
        {
            "label": "Działania do tego momentu",
            "color": "amber",
            "description": "Aby opisać, co zostało <strong>zrobione/nie zrobione do tej pory</strong> (już, jeszcze, kiedykolwiek, nigdy):",
            "examples": [
                {
                    "en": "The file has already been uploaded.",
                    "ua": "Plik został już pobrany."
                },
                {
                    "en": "The payment has not been received yet.",
                    "ua": "Płatność jeszcze nie otrzymana."
                },
                {
                    "en": "Has this book ever been translated?",
                    "ua": "Czy ta książka była kiedykolwiek tłumaczona?"
                }
            ]
        },
        {
            "label": "Okres do chwili obecnej",
            "color": "rose",
            "description": "W przypadku działań w <strong>okresie</strong> obejmującym chwilę obecną (dzisiaj, w tym tygodniu, od, na):",
            "examples": [
                {
                    "en": "Many changes have been made this year.",
                    "ua": "W tym roku wprowadzono wiele zmian."
                },
                {
                    "en": "The building has been renovated since 2020.",
                    "ua": "Od 2020 roku budynek jest w remoncie."
                },
                {
                    "en": "Three emails have been sent today.",
                    "ua": "Dzisiaj wysłano trzy listy."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po ma/ma: <strong>Temat + ma/miał + nie + był + V3</strong>",
            "examples": [
                {
                    "en": "The report has not been submitted yet.",
                    "ua": "Raport nie został jeszcze przesłany."
                },
                {
                    "en": "The documents have not been signed.",
                    "ua": "Dokumenty nie są podpisane."
                },
                {
                    "en": "The problem has not been solved.",
                    "ua": "Problem nie został rozwiązany."
                },
                {
                    "en": "The changes have not been approved.",
                    "ua": "Zmiany nie zostały zatwierdzone."
                }
            ]
        },
        {
            "label": "Skrócone formy",
            "color": "amber",
            "description": "Potocznie: <strong>nie był / nie był</strong>",
            "examples": [
                {
                    "en": "The email hasn't been sent yet.",
                    "ua": "List nie został jeszcze wysłany."
                },
                {
                    "en": "The tasks haven't been completed.",
                    "ua": "Zadanie nieukończone."
                },
                {
                    "en": "The decision hasn't been made.",
                    "ua": "Żadna decyzja nie została podjęta."
                }
            ]
        },
        {
            "label": "Typowe użycie z yet",
            "color": "sky",
            "description": "Słowo <strong>jeszcze</strong> (jeszcze) jest często używane w zdaniach przeczących:",
            "examples": [
                {
                    "en": "The order hasn't been delivered yet.",
                    "ua": "Zamówienie nie zostało jeszcze dostarczone."
                },
                {
                    "en": "The results haven't been announced yet.",
                    "ua": "Wyniki nie zostały jeszcze ogłoszone."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytanie Tak/Nie",
            "color": "blue",
            "description": "Na pierwszym miejscu jest <strong>Ma/Have</strong>: <strong>Ma/Miał + Temat + Był + V3?</strong>",
            "examples": [
                {
                    "en": "Has the report been finished?",
                    "ua": "Czy raport jest kompletny?"
                },
                {
                    "en": "Have the documents been signed?",
                    "ua": "Czy dokumenty są podpisane?"
                },
                {
                    "en": "Has the problem been solved?",
                    "ua": "Czy problem został rozwiązany?"
                },
                {
                    "en": "Have you ever been interviewed?",
                    "ua": "Czy kiedykolwiek udzielałeś wywiadu?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Jakie-słowo + ma/miał + Temat + był + V3?</strong>",
            "examples": [
                {
                    "en": "How many books have been sold?",
                    "ua": "Ile książek sprzedano?"
                },
                {
                    "en": "What has been done so far?",
                    "ua": "Co zostało zrobione do tej pory?"
                },
                {
                    "en": "Why has the meeting been cancelled?",
                    "ua": "Dlaczego spotkanie zostało odwołane?"
                },
                {
                    "en": "Where has the money been spent?",
                    "ua": "Na co wydano te pieniądze?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + zaimek + ma/ma (nie)</strong>:",
            "examples": [
                {
                    "en": "Has the email been sent? — Yes, it has. / No, it hasn't.",
                    "ua": "Czy list został wysłany? - Tak. / NIE."
                },
                {
                    "en": "Have they been informed? — Yes, they have. / No, they haven't.",
                    "ua": "Czy zostali poinformowani? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "6. Porównanie słowa aktywnego i pasywnego w czasie Present Perfect",
    "intro": "Jak zamienić zdanie czynne w stronę bierną:",
    "rows": [
        {
            "en": "Active: They have completed the project.",
            "ua": "Ukończyli projekt.",
            "note": "→ Passive: The project has been completed."
        },
        {
            "en": "Active: Someone has stolen my bike.",
            "ua": "Ktoś ukradł mój rower.",
            "note": "→ Passive: My bike has been stolen."
        },
        {
            "en": "Active: The company has hired new staff.",
            "ua": "Firma zatrudniła nowych pracowników.",
            "note": "→ Passive: New staff has been hired."
        },
        {
            "en": "Active: We have made a decision.",
            "ua": "Podjęliśmy decyzję.",
            "note": "→ Passive: A decision has been made."
        }
    ],
    "warning": "📌 Znaczniki czasu (właśnie, już, jeszcze niedawno) pozostają!"
}

{
    "title": "7. Porównanie wszystkich form biernych czasu teraźniejszego",
    "intro": "Różnica między trzema formami czasu teraźniejszego strony biernej:",
    "rows": [
        {
            "en": "Present Simple: The room is cleaned every day.",
            "ua": "Pokój jest sprzątany codziennie.",
            "note": "→ Regularne działanie"
        },
        {
            "en": "Present Continuous: The room is being cleaned now.",
            "ua": "Pokój jest teraz sprzątany.",
            "note": "→ Działanie już teraz"
        },
        {
            "en": "Present Perfect: The room has been cleaned.",
            "ua": "Pokój jest sprzątany (rezultat).",
            "note": "→ Zakończona akcja z wynikiem"
        }
    ],
    "warning": "📌 Present Perfect Passive podkreśla REZULTAT działania, a nie proces!"
}

{
    "title": "8. Znaczniki czasu dla strony biernej Present Perfect",
    "intro": "Typowe słowa i wyrażenia wskazujące na czas Present Perfect:",
    "items": [
        {
            "label": "Tylko",
            "title": "właśnie, niedawno, ostatnio",
            "subtitle": "Właśnie przesłano raport."
        },
        {
            "label": "Już/jeszcze",
            "title": "już, jeszcze, nadal",
            "subtitle": "Zadanie zostało już wykonane."
        },
        {
            "label": "Doświadczenie",
            "title": "kiedykolwiek, nigdy, wcześniej",
            "subtitle": "Czy kiedykolwiek wcześniej stosowano tę metodę?"
        },
        {
            "label": "Okres",
            "title": "w tym tygodniu/miesiącu/roku, dzisiaj, od, na",
            "subtitle": "W tym roku wprowadzono wiele ulepszeń."
        }
    ]
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomiń, byłem.",
            "wrong": "The report has completed.",
            "right": "✅ The report has been completed."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zły wybór ma/ma.",
            "wrong": "The documents has been signed.",
            "right": "✅ The documents have been signed."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie bycia i bycia.",
            "wrong": "The work has being done.",
            "right": "✅ The work has been done."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Używanie czasu Past Simple zamiast czasu Present Perfect.",
            "wrong": "The email was sent already.",
            "right": "✅ The email has already been sent."
        }
    ]
}
